script:
frappe.ui.form.on('Location', {

    validate(frm) {

        if (frm.doc.location_type === "Retailer" && !frm.doc.lead) {

            frappe.throw("Lead is mandatory when Location Type is Retailer");

        }

    }

});

frappe.ui.form.on('Request for Quotation', {

    recce_length(frm) {

        if (!frm.doc.recced_timestamp) {

            frm.set_value(
                "recced_timestamp",
                frappe.datetime.now_datetime()
            );

        }

    }

});

frappe.ui.form.on('Supplier Quotation', {

    request_for_quotation(frm) {

        if (frm.doc.request_for_quotation) {

            frappe.call({

                method: "frappe.client.get",

                args: {
                    doctype: "Request for Quotation",
                    name: frm.doc.request_for_quotation
                },

                callback: function(r) {

                    let rfq = r.message;

                    if (rfq) {

                        frm.set_value("location", rfq.location);
                        frm.set_value("lead", rfq.lead);

                        let recce_html = `
                        <div style="padding:10px">
                        <b>Recce Details</b><br><br>
                        Length : ${rfq.recce_length || ""}<br>
                        Height : ${rfq.recce_height || ""}<br>
                        Depth : ${rfq.recce_depth || ""}<br>
                        </div>
                        `;

                        frm.fields_dict.custom_recce_details.$wrapper.html(recce_html);

                    }

                }

            });

        }

    }

});

frappe.ui.form.on('Purchase Receipt', {

    validate(frm) {

        if (!frm.doc.qc_length || !frm.doc.qc_height || !frm.doc.qc_depth) {

            frappe.throw("QC Dimensions are mandatory");

        }

        if (!frm.doc.qc_photo1 || !frm.doc.qc_photo2) {

            frappe.throw("QC Photos are mandatory");

        }

    }

});

frappe.ui.form.on('Purchase Receipt', {

    refresh(frm) {

        if (frm.doc.docstatus === 1) {

            frm.add_custom_button("Generate Serial Number", function() {

                frappe.msgprint("Serial Number generation ready");

            });

        }

    }

});
